example.code:
// Basic conversion event
plausible('signup');

// Event with custom properties
plausible('signup', {
  props: {
    plan: 'premium',
    source: 'landing_page'
  }
});

// Revenue tracking (hosted Business plan only)
plausible('purchase', {
  revenue: { currency: 'USD', amount: 99.99 },
  props: { plan: 'Pro', billing: 'annual' }
});
